export default function CheckingDetail() {
  const [account, setAccount] = React.useState(null);
  const [txns, setTxns] = React.useState([]);
  const [loading, setLoading] = React.useState(true);

  React.useEffect(() => {
    async function load() {
      const accts = await tools.host_listAccounts({});
      const checking = (accts || []).find(a =>
        a.type === "checking" || (a.name && a.name.toLowerCase().includes("checking"))
      ) || (accts && accts[0]);
      setAccount(checking);
      if (checking) {
        const t = await tools.host_listAccountTransactions({ id: checking.id });
        setTxns(Array.isArray(t) ? t : (t && t.data) ? t.data : []);
      }
      setLoading(false);
    }
    load();
  }, []);

  if (loading) {
    return (
      <div style={{ padding: 24, fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-muted)" }}>
        Loading…
      </div>
    );
  }

  if (!account) {
    return (
      <div style={{ padding: 24, fontFamily: "var(--vendo-font-family)", color: "var(--vendo-color-muted)" }}>
        No checking account found.
      </div>
    );
  }

  const balanceDollars = typeof account.balanceCents === "number"
    ? fmt.money(account.balanceCents)
    : (account.balance != null ? fmt.money(Math.round(account.balance * 100)) : "—");

  const acctNumber = account.accountNumber || account.number || account.mask
    ? `••••${account.accountNumber || account.number || account.mask}`
    : "—";

  const statusTone = (status) => {
    if (!status) return "var(--vendo-color-muted)";
    const s = status.toLowerCase();
    if (s === "completed" || s === "posted" || s === "settled") return "#1a7f4b";
    if (s === "pending") return "#b45309";
    if (s === "failed" || s === "declined") return "var(--vendo-color-danger)";
    return "var(--vendo-color-muted)";
  };

  const statusLabel = (status) => {
    if (!status) return "—";
    return status.charAt(0).toUpperCase() + status.slice(1).toLowerCase().replace(/_/g, " ");
  };

  return (
    <div style={{ fontFamily: "var(--vendo-font-family)", display: "grid", gap: 24 }}>
      {/* Hero balance */}
      <div style={{
        background: "var(--vendo-color-surface)",
        border: "1px solid var(--vendo-color-border)",
        borderRadius: "var(--vendo-radius-large)",
        padding: "28px 28px 24px"
      }}>
        <div style={{ color: "var(--vendo-color-muted)", fontSize: 13, marginBottom: 6 }}>
          {account.name || "Checking account"}
        </div>
        <div style={{ fontSize: 40, fontWeight: 700, letterSpacing: "-1px", color: "var(--vendo-color-text)", lineHeight: 1.1 }}>
          {balanceDollars}
        </div>
        <div style={{ marginTop: 16, display: "flex", gap: 32, flexWrap: "wrap" }}>
          <div>
            <div style={{ color: "var(--vendo-color-muted)", fontSize: 12, marginBottom: 2 }}>Account number</div>
            <div style={{ fontSize: 15, color: "var(--vendo-color-text)", fontVariantNumeric: "tabular-nums" }}>{acctNumber}</div>
          </div>
          {account.routingNumber && (
            <div>
              <div style={{ color: "var(--vendo-color-muted)", fontSize: 12, marginBottom: 2 }}>Routing number</div>
              <div style={{ fontSize: 15, color: "var(--vendo-color-text)", fontVariantNumeric: "tabular-nums" }}>{account.routingNumber}</div>
            </div>
          )}
          {account.institution && (
            <div>
              <div style={{ color: "var(--vendo-color-muted)", fontSize: 12, marginBottom: 2 }}>Institution</div>
              <div style={{ fontSize: 15, color: "var(--vendo-color-text)" }}>{account.institution}</div>
            </div>
          )}
        </div>
      </div>

      {/* Recent transactions */}
      <div style={{
        background: "var(--vendo-color-surface)",
        border: "1px solid var(--vendo-color-border)",
        borderRadius: "var(--vendo-radius-large)",
        overflow: "hidden"
      }}>
        <div style={{ padding: "16px 20px 12px", borderBottom: "1px solid var(--vendo-color-border)" }}>
          <span style={{ fontWeight: 600, fontSize: 15, color: "var(--vendo-color-text)" }}>Recent transactions</span>
        </div>
        {txns.length === 0 ? (
          <div style={{ padding: 24, color: "var(--vendo-color-muted)", fontSize: 14 }}>
            No recent transactions on this account.
          </div>
        ) : (
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 14 }}>
            <thead>
              <tr style={{ background: "var(--vendo-color-background)" }}>
                <th style={{ textAlign: "left", padding: "10px 20px", color: "var(--vendo-color-muted)", fontWeight: 500, fontSize: 12 }}>Description</th>
                <th style={{ textAlign: "left", padding: "10px 12px", color: "var(--vendo-color-muted)", fontWeight: 500, fontSize: 12 }}>Date</th>
                <th style={{ textAlign: "left", padding: "10px 12px", color: "var(--vendo-color-muted)", fontWeight: 500, fontSize: 12 }}>Status</th>
                <th style={{ textAlign: "right", padding: "10px 20px", color: "var(--vendo-color-muted)", fontWeight: 500, fontSize: 12 }}>Amount</th>
              </tr>
            </thead>
            <tbody>
              {txns.map((tx, i) => {
                const cents = typeof tx.amountCents === "number" ? tx.amountCents
                  : typeof tx.amount === "number" ? Math.round(tx.amount * 100) : null;
                const isNeg = cents != null && cents < 0;
                const dateStr = tx.date || tx.createdAt || tx.postedAt || tx.timestamp;
                return (
                  <tr key={tx.id || i} style={{ borderTop: i === 0 ? "none" : "1px solid var(--vendo-color-border)" }}>
                    <td style={{ padding: "13px 20px", color: "var(--vendo-color-text)", maxWidth: 220 }}>
                      <div style={{ fontWeight: 500, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                        {tx.description || tx.merchant || tx.name || "—"}
                      </div>
                      {tx.category && (
                        <div style={{ color: "var(--vendo-color-muted)", fontSize: 12, marginTop: 2 }}>{tx.category}</div>
                      )}
                    </td>
                    <td style={{ padding: "13px 12px", color: "var(--vendo-color-muted)", whiteSpace: "nowrap" }}>
                      {dateStr ? new Date(dateStr).toLocaleDateString("en-US", { month: "short", day: "numeric" }) : "—"}
                    </td>
                    <td style={{ padding: "13px 12px" }}>
                      <span style={{
                        display: "inline-block",
                        padding: "2px 8px",
                        borderRadius: 99,
                        fontSize: 12,
                        fontWeight: 500,
                        background: "var(--vendo-color-background)",
                        color: statusTone(tx.status),
                        border: "1px solid var(--vendo-color-border)"
                      }}>
                        {statusLabel(tx.status)}
                      </span>
                    </td>
                    <td style={{ padding: "13px 20px", textAlign: "right", fontVariantNumeric: "tabular-nums", fontWeight: 600, color: "var(--vendo-color-text)" }}>
                      {cents != null ? fmt.money(Math.abs(cents)) : "—"}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
